using System;
using System.Collections.Generic;

class Program {
    static void Main() {
        var nums = new List<int> { 1, 2, 3 };
        nums.Add(4);
        nums.Add(5);
        Console.WriteLine(nums.Count);
        Console.WriteLine(nums[2]);
        nums.Remove(3);
        Console.WriteLine(string.Join(" ", nums));
    }
}

using System;
using System.Collections.Generic;

class Program {
    static void Main() {
        var v = new List<int> { 5, 2, 8, 1, 9, 3 };
        v.Sort();
        Console.WriteLine(string.Join(" ", v));
        Console.WriteLine(v.Contains(8));
        Console.WriteLine(v.IndexOf(8));
        v.Insert(0, 0);
        Console.WriteLine(string.Join(" ", v));
    }
}

using System;
using System.Collections.Generic;

class Program {
    static void Main() {
        var fruits = new List<string> { "apple", "banana", "cherry" };
        foreach (string fruit in fruits) {
            Console.WriteLine(fruit.ToUpper());
        }
        Console.WriteLine($"total: {fruits.Count}");
    }
}

using System;
using System.Collections.Generic;

class Program {
    static void Main() {
        var scores = new Dictionary<string, int>();
        scores["Alice"] = 95;
        scores["Bob"]   = 82;
        scores.Add("Carol", 91);
        Console.WriteLine(scores["Alice"]);
        Console.WriteLine(scores.ContainsKey("Dave"));
        Console.WriteLine(scores.Count);
    }
}

using System;
using System.Collections.Generic;

class Program {
    static void Main() {
        var capitals = new Dictionary<string, string> {
            { "France", "Paris" },
            { "Japan", "Tokyo" },
            { "USA", "Washington" }
        };
        foreach (var kv in capitals) {
            Console.WriteLine($"{kv.Key}: {kv.Value}");
        }
    }
}

